import{_ as e,o as a,c as r,a as n}from"./app.1f065ff2.js";const f=JSON.parse('{"title":"Java\u5185\u5B58\u6A21\u578B","description":"","frontmatter":{},"headers":[{"level":2,"title":"\u6982\u8FF0","slug":"\u6982\u8FF0","link":"#\u6982\u8FF0","children":[]},{"level":2,"title":"\u4E3B\u5185\u5B58\u548C\u672C\u5730\u5185\u5B58","slug":"\u4E3B\u5185\u5B58\u548C\u672C\u5730\u5185\u5B58","link":"#\u4E3B\u5185\u5B58\u548C\u672C\u5730\u5185\u5B58","children":[]},{"level":2,"title":"Happens-Before\u539F\u5219","slug":"happens-before\u539F\u5219","link":"#happens-before\u539F\u5219","children":[]},{"level":2,"title":"\u5E76\u53D1\u7279\u6027\u7684\u5B9E\u73B0","slug":"\u5E76\u53D1\u7279\u6027\u7684\u5B9E\u73B0","link":"#\u5E76\u53D1\u7279\u6027\u7684\u5B9E\u73B0","children":[{"level":3,"title":"\u539F\u5B50\u6027","slug":"\u539F\u5B50\u6027","link":"#\u539F\u5B50\u6027","children":[]},{"level":3,"title":"\u53EF\u89C1\u6027","slug":"\u53EF\u89C1\u6027","link":"#\u53EF\u89C1\u6027","children":[]},{"level":3,"title":"\u6709\u5E8F\u6027","slug":"\u6709\u5E8F\u6027","link":"#\u6709\u5E8F\u6027","children":[]}]}],"relativePath":"Java/Java\u8BED\u8A00\u7279\u6027/Java\u5185\u5B58\u6A21\u578B.md"}'),t={name:"Java/Java\u8BED\u8A00\u7279\u6027/Java\u5185\u5B58\u6A21\u578B.md"},s=n('<h1 id="java\u5185\u5B58\u6A21\u578B" tabindex="-1">Java\u5185\u5B58\u6A21\u578B <a class="header-anchor" href="#java\u5185\u5B58\u6A21\u578B" aria-hidden="true">#</a></h1><h2 id="\u6982\u8FF0" tabindex="-1">\u6982\u8FF0 <a class="header-anchor" href="#\u6982\u8FF0" aria-hidden="true">#</a></h2><p><strong>Java\u5185\u5B58\u6A21\u578B</strong>\uFF08Java Memory Model\uFF09\u662F\u4E3A\u4E86\u907F\u514D\u4E0D\u540C\u64CD\u4F5C\u7CFB\u7EDF\u4E4B\u95F4\u5185\u5B58\u6A21\u578B\u7684\u4E0D\u540C\uFF0C\u4ECE\u800C\u5BFC\u81F4\u591A\u7EBF\u7A0B\u5DE5\u4F5C\u65F6\u7684\u7ED3\u679C\u4E0D\u4E00\u81F4\u95EE\u9898\u3002</p><p>\u4E00\u65B9\u9762\u6765\u8BF4\uFF0C\u7531\u4E8E\u4E0D\u540CCPU\u7684Cache\u7ED3\u6784\u4E0D\u540C\u5BFC\u81F4<strong>\u64CD\u4F5C\u7CFB\u7EDF\u7684\u5185\u5B58\u6A21\u578B</strong>\u4E0D\u540C\uFF0C\u53E6\u4E00\u65B9\u9762\uFF0C\u64CD\u4F5C\u7CFB\u7EDF\u4F1A\u5BF9<strong>\u4EE3\u7801\u8FDB\u884C\u6307\u4EE4\u91CD\u6392\u5E8F</strong>\uFF0C\u4F46\u662F\u5B9E\u9645\u4E0A\u8FD9\u4E2A\u64CD\u4F5C\u65E0\u6CD5\u4FDD\u8BC1\u5728\u591A\u7EBF\u7A0B\u60C5\u51B5\u4E0B\u7684\u6B63\u786E\u6027\uFF08\u5373\uFF0C\u5B9E\u9645\u6267\u884C\u4EE3\u7801\u7684\u987A\u5E8F\u5E76\u4E0D\u4E00\u5B9A\u662F\u6211\u4EEC\u7F16\u5199\u4EE3\u7801\u7684\u987A\u5E8F\uFF09\uFF1B\u56E0\u6B64\u9700\u8981Java<strong>\u5B9A\u4E49\u4E00\u5957\u89C4\u8303</strong>\u6765\u6765\u4FDD\u8BC1\u5E76\u53D1\u7F16\u7A0B\u7684\u53EF\u884C\u6027\uFF0C\u8BA9\u5F00\u53D1\u8005\u65E0\u9700\u53BB\u987E\u53CA\u4E0D\u540C\u5E73\u53F0\u5BFC\u81F4\u7684\u5E76\u53D1\u7279\u6027\u7684\u4E0D\u540C\u3002</p><h2 id="\u4E3B\u5185\u5B58\u548C\u672C\u5730\u5185\u5B58" tabindex="-1">\u4E3B\u5185\u5B58\u548C\u672C\u5730\u5185\u5B58 <a class="header-anchor" href="#\u4E3B\u5185\u5B58\u548C\u672C\u5730\u5185\u5B58" aria-hidden="true">#</a></h2><p>\u6240\u6709\u7EBF\u7A0B\u521B\u5EFA\u7684<strong>\u5B9E\u4F8B\u5BF9\u8C61\u53CA\u5176\u6210\u5458\u5B57\u6BB5</strong>\u90FD\u5B58\u50A8\u5728\u4E3B\u5185\u5B58\u4E2D\uFF0C\u800C<strong>\u65B9\u6CD5\u4E2D\u7684\u5C40\u90E8\u53D8\u91CF\u5F15\u7528\u5219\u5B58\u50A8\u5728\u7EBF\u7A0B\u6808</strong>\u4E2D\u3002</p><p>\u5F53\u7EBF\u7A0B\u4E4B\u95F4\u9700\u8981\u8FDB\u884C\u901A\u4FE1\uFF0C\u5373\u5BF9\u540C\u4E00\u4E2A<strong>\u5171\u4EAB\u53D8\u91CF</strong>\u8FDB\u884C\u64CD\u4F5C\u65F6\uFF0C\u6211\u4EEC\u89C4\u5B9A\u6240\u6709\u7684\u5171\u4EAB\u53D8\u91CF\u90FD\u5B58\u50A8\u5728\u4E3B\u5185\u5B58\u4E2D\uFF08\u5B9E\u9645\u64CD\u4F5C\u7684\u5171\u4EAB\u53D8\u91CF\u5F80\u5F80\u90FD\u662F\u7C7B\u7684\u67D0\u4E2A\u6210\u5458\u5B57\u6BB5\uFF09\uFF0C\u800C\u6BCF\u4E2A\u7EBF\u7A0B\u90FD\u6709\u4E00\u4E2A<strong>\u865A\u62DF\u7684\uFF0C\u5E76\u4E0D\u5B58\u5728\u7684</strong>\u672C\u5730\u5185\u5B58\uFF0C\u5728\u9700\u8981\u64CD\u4F5C\u65F6\uFF0C\u7EBF\u7A0B\u5148\u5C06\u4E3B\u5185\u5B58\u4E2D\u7684\u5171\u4EAB\u53D8\u91CF\u590D\u5236\u4E00\u4EFD\u526F\u672C\u5230\u672C\u5730\u5185\u5B58\uFF0C\u5E76\u5BF9\u672C\u5730\u5185\u5B58\u4E0A\u7684\u526F\u672C\u8FDB\u884C\u4FEE\u6539\uFF0C\u4FEE\u6539\u5B8C\u6BD5\u540E\u518D\u5C06\u526F\u672C\u66F4\u65B0\u5230\u4E3B\u5185\u5B58\u4E0A\u7684\u5171\u4EAB\u53D8\u91CF\u3002</p><p><img src="https://pic2.zhimg.com/v2-bd607bd9a5598a8330ad329033e04b91_r.jpg" alt=""></p><p>\u8FD9\u4E00\u70B9\u4FDD\u8BC1\u4E86\u7EBF\u7A0B\u4E4B\u95F4\u5171\u4EAB\u53D8\u91CF\u7684\u53EF\u89C1\u6027\uFF0C\u4F46\u662F\u4E5F\u5BFC\u81F4\u4E86\u4E00\u4E2A\u95EE\u9898\uFF1A<strong>\u7EBF\u7A0BB\u8BFB\u53D6\u5230\u7684\u5171\u4EAB\u53D8\u91CF\u65E0\u6CD5\u786E\u5B9A\u662F\u7EBF\u7A0BA\u4FEE\u6539\u524D\u8FD8\u662F\u4FEE\u6539\u540E\u7684</strong></p><h2 id="happens-before\u539F\u5219" tabindex="-1">Happens-Before\u539F\u5219 <a class="header-anchor" href="#happens-before\u539F\u5219" aria-hidden="true">#</a></h2><p>JMM\u7684\u6B63\u786E\u8FD0\u884C\u662F\u57FA\u4E8E\u4E00\u7CFB\u5217Happens-Before\u539F\u5219\u7684</p><p>Happens-Before\u539F\u5219\u6307\u660E\u4E86\u4E00\u7CFB\u5217<strong>\u53EF\u4EE5\u88AB\u91CD\u6392\u5E8F</strong>\u7684\u64CD\u4F5C\u548C\u4E00\u7CFB\u5217<strong>\u4E0D\u80FD\u88AB\u91CD\u6392\u5E8F</strong>\u7684\u64CD\u4F5C\uFF0C\u5982\u679C\u6211\u4EEC\u8BF4\u64CD\u4F5CA happens-before \u64CD\u4F5CB\uFF0C\u90A3\u4E48\u64CD\u4F5CA\u7684\u7ED3\u679C\u5C31\u662F\u5BF9\u64CD\u4F5CB\u53EF\u89C1\u7684\uFF0C\u5982\u679C\u6307\u4EE4\u91CD\u6392\u5E8F\u65E0\u6CD5\u4FDD\u8BC1\u8FD9\u4E00\u70B9\uFF0C\u90A3\u4E48JMM\u5C31\u4F1A\u7981\u6B62\u8FD9\u4E2A\u64CD\u4F5C\u3002</p><p>\u4E3E\u4F8B\u6765\u8BF4\uFF0C\u7EBF\u7A0BA\u7684\u67D0\u4E00\u4E2A\u64CD\u4F5C\u5982\u679Chappens-before\u7EBF\u7A0BB\u7684\u67D0\u4E00\u4E2A\u64CD\u4F5C\uFF0C\u90A3\u4E48JMM\u5C31\u4F1A\u4FDD\u8BC1\u7EBF\u7A0BA\u7684\u8FD9\u4E00\u6B65\u64CD\u4F5C\u4E00\u5B9A\u662F\u5BF9\u4E8E\u7EBF\u7A0BB\u53EF\u89C1\u7684\uFF08\u901A\u5E38\u662F\u5148\u6267\u884C\uFF09</p><p>happens-before\u89C4\u5219\u4E00\u5171\u6709\u516B\u6761\uFF0C\u5176\u4E2D\u5E38\u7528\u7684\u6709\u4E94\u6761</p><ul><li><strong>\u7A0B\u5E8F\u987A\u5E8F\u89C4\u5219</strong>\uFF1A\u4E00\u4E2A\u7EBF\u7A0B\u5185\uFF0C\u6309\u7167\u4EE3\u7801\u987A\u5E8F\uFF0C\u4E66\u5199\u5728\u524D\u9762\u7684\u64CD\u4F5C happens-before \u4E8E\u4E66\u5199\u5728\u540E\u9762\u7684\u64CD\u4F5C</li><li><strong>\u89E3\u9501\u89C4\u5219</strong>\uFF1A\u89E3\u9501 happens-before \u4E8E\u52A0\u9501</li><li><strong>volatile\u53D8\u91CF\u89C4\u5219</strong>\uFF1A\u5BF9\u4E00\u4E2A volatile \u53D8\u91CF\u7684\u5199\u64CD\u4F5C happens-before \u4E8E\u540E\u9762\u5BF9\u8FD9\u4E2A volatile \u53D8\u91CF\u7684\u8BFB\u64CD\u4F5C\u3002\u8BF4\u767D\u4E86\u5C31\u662F\u5BF9 volatile \u53D8\u91CF\u7684\u5199\u64CD\u4F5C\u7684\u7ED3\u679C\u5BF9\u4E8E\u53D1\u751F\u4E8E\u5176\u540E\u7684\u4EFB\u4F55\u64CD\u4F5C\u90FD\u662F\u53EF\u89C1\u7684</li><li><strong>\u4F20\u9012\u89C4\u5219</strong>\uFF1A\u5982\u679C A happens-before B\uFF0C\u4E14 B happens-before C\uFF0C\u90A3\u4E48 A happens-before C</li><li><strong>\u7EBF\u7A0B\u542F\u52A8\u89C4\u5219</strong>\uFF1AThread \u5BF9\u8C61\u7684 start()\u65B9\u6CD5 happens-before \u4E8E\u6B64\u7EBF\u7A0B\u7684\u6BCF\u4E00\u4E2A\u52A8\u4F5C</li></ul><p><img src="https://oss.javaguide.cn/github/javaguide/java/concurrent/image-20220731084604667.png" alt=""></p><p>\u5BF9\u4E8E\u7A0B\u5E8F\u5458\u6765\u8BF4\uFF1A\u4ED6\u4EEC\u53EA\u8D1F\u8D23\u5B9E\u73B0\u4E86\u9AD8\u6548\u7684Java\u5E76\u53D1\u4EE3\u7801\u7F16\u7A0B\u90E8\u5206\uFF0C\u800C\u4FDD\u8BC1\u4E86Java\u5E76\u53D1\u4EE3\u7801\u7684<strong>\u6B63\u786E\u8FD0\u884C</strong>\u662F\u7531JMM\u5B9E\u73B0\u7684\uFF0C\u5B83\u57FA\u4E8E\u4E00\u7CFB\u5217happens-before\u89C4\u5219\uFF0C<strong>\u5BF9\u4E8E\u4F1A\u5F71\u54CD\u5E76\u53D1\u6B63\u786E\u6027\u7684\u91CD\u6392\u5E8F\u89C4\u5219\u4E88\u4EE5\u7981\u6B62\uFF0C\u5BF9\u4E8E\u65E0\u4F24\u5927\u96C5\u7684\u91CD\u6392\u5E8F\u4F18\u5316\u5219\u5141\u8BB8</strong></p><h2 id="\u5E76\u53D1\u7279\u6027\u7684\u5B9E\u73B0" tabindex="-1">\u5E76\u53D1\u7279\u6027\u7684\u5B9E\u73B0 <a class="header-anchor" href="#\u5E76\u53D1\u7279\u6027\u7684\u5B9E\u73B0" aria-hidden="true">#</a></h2><h3 id="\u539F\u5B50\u6027" tabindex="-1">\u539F\u5B50\u6027 <a class="header-anchor" href="#\u539F\u5B50\u6027" aria-hidden="true">#</a></h3><p>\u4E00\u7EC4\u5177\u6709\u539F\u5B50\u6027\u7684\u64CD\u4F5C\uFF0C\u5FC5\u987B\u4E00\u6B21\u6027\u6267\u884C\u5B8C\u6BD5\u800C\u4E0D\u88AB\u4E2D\u65AD\uFF0C\u8981\u4E48\u5C31\u90FD\u4E0D\u6267\u884C\u3002\u5728Java\u4E2D\u539F\u5B50\u6027\u7531<code>synchronized</code>\u5173\u952E\u5B57\u548C\u5404\u79CDLock\u9501\u5B9E\u73B0\u7684</p><p>\u800C\u539F\u5B50\u7C7B\u662F\u57FA\u4E8ECAS\u7B97\u6CD5\u4FDD\u8BC1\u4E86\u539F\u5B50\u64CD\u4F5C\u7684\u6B63\u786E\u6027</p><h3 id="\u53EF\u89C1\u6027" tabindex="-1">\u53EF\u89C1\u6027 <a class="header-anchor" href="#\u53EF\u89C1\u6027" aria-hidden="true">#</a></h3><p>\u5982\u679C\u4E00\u4E2A\u7EBF\u7A0B\u4FEE\u6539\u4E86\u67D0\u4E2A\u5171\u4EAB\u53D8\u91CF\uFF0C\u90A3\u4E48\u5176\u4ED6\u7EBF\u7A0B\u5E94\u5F53\u7ACB\u5373\u770B\u5230\u5171\u4EAB\u53D8\u91CF\u7684\u6700\u65B0\u503C\uFF0C\u4F46\u662F\u7531\u4E8EJMM\u6A21\u578B\u7684\u7279\u6027\uFF0C\u8FD9\u4E00\u70B9\u5E76\u4E0D\u80FD\u5F97\u5230\u4FDD\u8BC1</p><p>\u56E0\u6B64Java\u9700\u8981\u901A\u8FC7<code>volatile</code>\u5173\u952E\u5B57\u6765\u5B9E\u73B0\uFF0C\u8FD9\u4E2A\u5173\u952E\u5B57\u544A\u8BC9\u7EBF\u7A0B\u8BE5\u53D8\u91CF\u5E94\u5F53<strong>\u8D8A\u8FC7\u672C\u5730\u5185\u5B58</strong>\uFF0C\u76F4\u63A5\u53BB\u64CD\u4F5C<strong>\u4E3B\u5185\u5B58\u4E2D\u7684\u5171\u4EAB\u53D8\u91CF</strong></p><h3 id="\u6709\u5E8F\u6027" tabindex="-1">\u6709\u5E8F\u6027 <a class="header-anchor" href="#\u6709\u5E8F\u6027" aria-hidden="true">#</a></h3><p>\u57FA\u4E8E\u4E0A\u8FF0happen-before\u4E2D\u7684volatile\u53D8\u91CF\u89C4\u5219\uFF0C\u53EF\u4EE5\u901A\u8FC7\u5BF9\u5171\u4EAB\u53D8\u91CF\u58F0\u660E\u4E3Avolatile\u6765\u4FDD\u8BC1\u8BFB\u5199\u64CD\u4F5C\u7684\u6709\u5E8F\u6027\uFF0C\u800C\u4E0D\u4F1A\u88AB\u91CD\u6392\u5E8F\u6253\u4E71</p>',26),o=[s];function i(p,l,h,d,g,c){return a(),r("div",null,o)}const _=e(t,[["render",i]]);export{f as __pageData,_ as default};
